import * as fs from 'fs';
import syncLineReaderFactory from './syncLineReader.mjs';

function parseLine (input) {
  const [str, n, s] = input
  .trim()
  .split(/\s+/g)
  ;

  return [str, parseInt(n), s];
}

export function loadSync (file) {
  const result = [];
  const reader = syncLineReaderFactory(file);
  let line;
  while ((line = reader.getLine()) !== null) {
    if (line.trim() !== '') result.push(parseLine(line));
  }
  return result;
}

export function load (file) {
  return new Promise(function (resolve, reject) {
    const stream = fs.createReadStream(file, 'utf8');
    const dict = [];
    let buf = '';
    stream.on('data', chunk => {
      buf += chunk;
      const lines = buf.split(/\r\n?|\n/g);
      const len = lines.length;
      for (let n = 0; n < len - 1; n++) {
        if (lines[n].trim() !== '') dict.push(parseLine(lines[n]));
      }
      if (len) buf = lines[len - 1];
    });
    stream.on('end', () => {
      if (buf.length) dict.push(parseLine(buf));
      resolve(dict);
    });
    stream.on('error', e => {
      reject(e);
    });
  });
}
